class Solution:
    def maxHappyGroups(self, batchSize, groups):
        import sys
        from functools import lru_cache
        sys.setrecursionlimit(100000)
        rems = tuple(g % batchSize for g in groups if g % batchSize != 0)
        base = len(groups) - len(rems)
        from collections import Counter
        cnt = Counter(rems)
        # state: counts of each remainder 1..batchSize-1, plus current leftover
        @lru_cache(maxsize=None)
        def dfs(state, leftover):
            counts = list(state)
            best = 0
            any_left = False
            for r in range(1, batchSize):
                if counts[r] > 0:
                    any_left = True
                    counts[r] -= 1
                    add = 1 if leftover == 0 else 0
                    val = add + dfs(tuple(counts), (leftover + r) % batchSize)
                    if val > best:
                        best = val
                    counts[r] += 1
            if not any_left:
                return 0
            return best
        init = tuple(cnt.get(r, 0) for r in range(batchSize))
        return base + dfs(init, 0)

