class Solution:
    def maxHappyGroups(self, batchSize, groups):
        from functools import lru_cache
        from collections import Counter
        cnt = Counter(g % batchSize for g in groups)
        happy = cnt[0]
        del cnt[0]
        # pair complementary remainders greedily
        for r in range(1, batchSize // 2 + 1):
            c = batchSize - r
            if r == c:
                happy += cnt[r] // 2
                cnt[r] %= 2
            else:
                m = min(cnt[r], cnt[c])
                happy += m
                cnt[r] -= m
                cnt[c] -= m
        state0 = tuple(cnt.get(r, 0) for r in range(batchSize))
        @lru_cache(maxsize=None)
        def dfs(state, left):
            counts = list(state)
            best = -1
            for r in range(1, batchSize):
                if counts[r] > 0:
                    counts[r] -= 1
                    add = 1 if left == 0 else 0
                    v = add + dfs(tuple(counts), (left + r) % batchSize)
                    counts[r] += 1
                    if v > best:
                        best = v
            return 0 if best < 0 else best
        return happy + dfs(state0, 0)

