var maxHappyGroups = function(batchSize, groups) {
    const cnt = new Array(batchSize).fill(0);
    for (const g of groups) cnt[g % batchSize]++;
    let happy = cnt[0];
    cnt[0] = 0;
    for (let r = 1; r <= Math.floor(batchSize / 2); r++) {
        const c = batchSize - r;
        if (r === c) {
            happy += Math.floor(cnt[r] / 2);
            cnt[r] %= 2;
        } else {
            const m = Math.min(cnt[r], cnt[c]);
            happy += m;
            cnt[r] -= m;
            cnt[c] -= m;
        }
    }
    const memo = new Map();
    const dfs = (counts, left) => {
        const key = counts.join(',') + '|' + left;
        if (memo.has(key)) return memo.get(key);
        let best = -1;
        for (let r = 1; r < batchSize; r++) {
            if (counts[r] > 0) {
                counts[r]--;
                const add = left === 0 ? 1 : 0;
                const v = add + dfs(counts, (left + r) % batchSize);
                counts[r]++;
                if (v > best) best = v;
            }
        }
        const res = best < 0 ? 0 : best;
        memo.set(key, res);
        return res;
    };
    return happy + dfs(cnt.slice(), 0);
};
